/// <summary>
/// For storing the Purchase order info which retrieved and transform from the IF table.
/// </summary>
class KJP_SM_ArrivalResultsPurchInfoClass
{
    private PurchLine                       purchLine;
    private PurchIdBase                     purchId;
    private TradeLineNumber                 lineNumber;
    private PurchOrderedQty                 purchQty;
    private PurchLineConfirmedReceiptDate   confirmedDlv;

}

Method.Source:
/// <summary>
/// Constructor for current class
/// </summary>
/// <returns>Instance of current class</returns>
public static KJP_SM_ArrivalResultsPurchInfoClass construct()
{
    return new KJP_SM_ArrivalResultsPurchInfoClass();
}

    /// <summary>
    /// Get the purchase line info from business table base on PurchId and LineNumber retrieved from the IF table.
    /// </summary>
    /// <returns>true if the purchase order line is OK; otherwise, false.</returns>
    public boolean getPurchInfo()
    {
        UnitOfMeasureSymbol salesUnit;
        UnitOfMeasureSymbol inventUnit;
        boolean ret = true;

        purchLine       = PurchLine::find(purchId, lineNumber);

        // If purchase order line is not an open order line, skip
        if (!purchLine.isOpenOrder())
        {
            ret = checkFailed(strFmt("@KJP:KJP500635", purchId, lineNumber));
            return ret;
        }

        salesUnit       = InventTableModule::getUnitIdByModuleType(purchLine.ItemId, ModuleInventPurchSales::Sales);
        inventUnit      = InventTableModule::getUnitIdByModuleType(purchLine.ItemId, ModuleInventPurchSales::Invent);

        purchQty        = EcoResProductUnitConverter::convertGivenUnitSymbolsForReleasedProduct(
                            purchLine.ItemId,
                            purchLine.InventDimId,
                            purchQty,
                            salesUnit,
                            inventUnit);

        return ret;
    }

/// <summary>
/// Parameterized the Purchase Line
/// </summary>
/// <returns>PurchLine</returns>
public PurchLine parmPurchLine()
{
    return purchLine;
}

/// <summary>
/// Parameterized the InventTransId of Purchase Line
/// </summary>
/// <returns>TradeInventTransId</returns>
public TradeInventTransId parmInventTransId()
{
    return this.parmPurchLine().InventTransId;
}

/// <summary>
/// Parameterized the ItemId of Purchase Line
/// </summary>
/// <returns>ItemId</returns>
public ItemId parmItemId()
{
    return this.parmPurchLine().ItemId;
}

/// <summary>
/// Parameterized the InventDimId of Purchase Line
/// </summary>
/// <returns>InventDimId</returns>
public InventDimId parmInventDimId()
{
    return this.parmPurchLine().InventDimId;
}

    /// <summary>
    /// VoucherNumber - Purch Id
    /// </summary>
    /// <param name = "_purchId">Purch Id</param>
    /// <returns>Purch Id</returns>
    public PurchIdBase parmPurchId(PurchIdBase _purchId = purchId)
    {
        purchId = _purchId;

        return purchId;
    }

    /// <summary>
    /// LineNo - Line Number
    /// </summary>
    /// <param name = "_lineNumber">Line Number</param>
    /// <returns>Line Number</returns>
    public TradeLineNumber parmLineNumber(TradeLineNumber _lineNumber = lineNumber)
    {
        lineNumber = _lineNumber;

        return lineNumber;
    }

    /// <summary>
    /// ArrivalTotalNumber - Purch Qty
    /// </summary>
    /// <param name = "_purchQty">Purch Qty</param>
    /// <returns>Purch Qty</returns>
    public PurchOrderedQty parmPurchQty(PurchOrderedQty _purchQty = purchQty)
    {
        purchQty = _purchQty;

        return purchQty;
    }

    /// <summary>
    /// ReceiptDate - Confirmed Delivery date
    /// </summary>
    /// <param name = "_confirmedDlv">Confirmed Delivery Date</param>
    /// <returns>Confirmed Delivery Date</returns>
    public PurchLineConfirmedReceiptDate parmConfirmedDlv(PurchLineConfirmedReceiptDate _confirmedDlv = confirmedDlv)
    {
        confirmedDlv = _confirmedDlv;

        return confirmedDlv;
    }
